import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import "./ViewEmployee.css";

function ViewEmployee() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [employee, setEmployee] = useState(null);

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  /* ---------------- LOAD EMPLOYEE SAFELY ---------------- */
  useEffect(() => {
    const employees =
      JSON.parse(localStorage.getItem("employees")) || [];

    let foundEmployee = null;

    // EMPLOYEE: can view only own profile
    if (loggedUser?.role === "Employee") {
      foundEmployee = employees.find(
        (e) =>
          String(e.empId) === String(loggedUser.empId) ||
          String(e.id) === String(loggedUser.empId)
      );
    } 
    // ADMIN: can view via URL param
    else {
      foundEmployee = employees.find(
        (emp) =>
          String(emp.id) === String(id) ||
          String(emp.empId) === String(id)
      );
    }

    setEmployee(foundEmployee);
  }, [id, loggedUser]);

  /* ---------------- NOT FOUND ---------------- */
  if (!employee) {
    return (
      <p style={{ padding: "20px" }}>
        Employee not found
      </p>
    );
  }

  return (
    <div className="view-employee-page">
      <h2>Employee Details</h2>

      {/* ================= CARD ================= */}
      <div className="employee-card">

        <div className="details-grid">

          {/* -------- LEFT COLUMN -------- */}
          <div className="details-column">
            <p>
              <strong>Name:</strong>{" "}
              {employee.firstName} {employee.lastName}
            </p>
            <p>
              <strong>Email:</strong> {employee.email}
            </p>
            <p>
              <strong>Employee ID:</strong> {employee.empId}
            </p>
            <p>
              <strong>Date of Birth:</strong> {employee.dob}
            </p>
            <p>
              <strong>Gender:</strong> {employee.gender}
            </p>
            <p>
              <strong>Department:</strong> {employee.department}
            </p>
            <p>
              <strong>Marital Status:</strong>{" "}
              {employee.maritalStatus}
            </p>
          </div>

          {/* -------- RIGHT COLUMN -------- */}
          <div className="details-column">
            <p>
              <strong>Designation:</strong>{" "}
              {employee.designation}
            </p>
            <p>
              <strong>Salary:</strong> {employee.salary}
            </p>
            <p>
              <strong>Role:</strong> {employee.role}
            </p>

            <p className="section-title">
              Bank Details
            </p>
            <p>
              <strong>Bank Name:</strong>{" "}
              {employee.bankName || "Not Provided"}
            </p>
            <p>
              <strong>Account Number:</strong>{" "}
              {employee.accountNumber || "Not Provided"}
            </p>
            <p>
              <strong>IFSC:</strong>{" "}
              {employee.ifsc || "Not Provided"}
            </p>

            <p className="section-title">
              Educational Details
            </p>
            <p>
              <strong>Qualification:</strong>{" "}
              {employee.qualification || "Not Provided"}
            </p>
            <p>
              <strong>University:</strong>{" "}
              {employee.university || "Not Provided"}
            </p>
            <p>
              <strong>Passing Year:</strong>{" "}
              {employee.passingYear || "Not Provided"}
            </p>
          </div>

        </div>
      </div>

      {/* ================= BACK BUTTON ================= */}
      <button
        className="back-btn"
        onClick={() => navigate(-1)}
      >
        Back
      </button>
    </div>
  );
}

export default ViewEmployee;
